136	async function freePort(): Promise<number> {
137		return new Promise((resolve, reject) => {
138			const server = net.createServer();
139			server.once('error', reject);
140			server.listen(0, '127.0.0.1', () => {
141				const address = server.address();
142				if (!address || typeof address === 'string') {
143					server.close(() => reject(new Error('could not allocate port')));
144					return;
145				}
146				const port = address.port;
147				server.close(() => resolve(port));
148			});
149		});
150	}
