189	async function startRealDdxServer(fixtureRoot: string): Promise<RealServer> {
190		const port = await freePort();
191		const bin = ensureDdxBinary();
192		const child = spawn(bin, ['server', '--port', String(port), '--tsnet=false'], {
193			cwd: fixtureRoot,
194			env: {
195				...process.env,
196				DDX_NODE_NAME: 'graph-e2e-node',
197				XDG_DATA_HOME: path.join(fixtureRoot, '.xdg-data')
198			}
199		});
200		child.stdout.resume();
201		child.stderr.resume();
202		const baseURL = `https://127.0.0.1:${port}`;
203		const api = await playwrightRequest.newContext({ baseURL, ignoreHTTPSErrors: true });
204	
205		let lastError: unknown;
206		for (let i = 0; i < 80; i++) {
207			if (child.exitCode !== null) {
208				throw new Error(`ddx server exited early with code ${child.exitCode}`);
209			}
210			try {
211				const resp = await api.get('/api/health', { timeout: 500 });
212				if (resp.ok()) {
213					const infoResp = await api.post('/graphql', {
214						data: {
215							query: `query E2EProjectInfo {
216								nodeInfo { id name }
217								projects { edges { node { id name path } } }
218							}`
219						}
220					});
221					const payload = (await infoResp.json()) as {
222						data: {
223							nodeInfo: { id: string };
224							projects: { edges: Array<{ node: { id: string } }> };
225						};
226					};
227					const projectId = payload.data.projects.edges[0]?.node.id;
228					if (!projectId) throw new Error('ddx server returned no registered project');
229					return {
230						api,
231						nodeId: payload.data.nodeInfo.id,
232						projectId,
233						process: child,
234						root: fixtureRoot
235					};
236				}
237			} catch (err) {
238				lastError = err;
239			}
240			await new Promise((resolve) => setTimeout(resolve, 125));
241		}
242	
243		child.kill();
244		await api.dispose();
245		throw new Error(`ddx server did not become healthy: ${String(lastError)}`);
246	}
