248	async function stopRealDdxServer(server: RealServer) {
249		await server.api.dispose();
250		if (server.process.exitCode === null) {
251			server.process.kill();
252			await Promise.race([
253				new Promise((resolve) => server.process.once('exit', resolve)),
254				new Promise((resolve) => {
255					setTimeout(() => {
256						if (server.process.exitCode === null) server.process.kill('SIGKILL');
257						resolve(undefined);
258					}, 2000);
259				})
260			]);
261		}
262		fs.rmSync(server.root, { recursive: true, force: true });
263	}
